public sealed class EatingWorkCoordinatorV3
{
    private readonly MercenaryNeedsSessionV3 _needs;private readonly ResourceSessionV3 _resources;private readonly MercenarySessionV3 _mercenaries;private readonly MercenaryControlSessionV3 _control;private readonly MercenaryWorkSessionV3 _work;private readonly IMercenaryNavigationWorldQueryV3 _query;private readonly string _playerId,_companyId;private readonly Dictionary<string,EatingWorkStateV3> _active=new(StringComparer.Ordinal);private long _revision;
    public EatingWorkCoordinatorV3(MercenaryNeedsSessionV3 needs,ResourceSessionV3 resources,MercenarySessionV3 mercenaries,MercenaryControlSessionV3 control,MercenaryWorkSessionV3 work,IMercenaryNavigationWorldQueryV3 query,string playerId,string companyId){_needs=needs;_resources=resources;_mercenaries=mercenaries;_control=control;_work=work;_query=query;_playerId=playerId;_companyId=companyId;}
    public int ActiveCount=>_active.Count;public EatingDiagnosticsV3 Diagnostics{get;}=new();public event Action? Changed;public event Action? ResourcesChanged;
    public bool TryIssueManual(string mercenaryId,out string reason)=>TryIssue(mercenaryId,EatingCommandSourceV3.DirectOrder,out reason);
    public bool TryIssueAuto(string mercenaryId,out string reason){Diagnostics.AutoEatCandidateCount++;bool ok=TryIssue(mercenaryId,EatingCommandSourceV3.NeedAutoEat,out reason);Diagnostics.LastAutoEatDecision=ok?"Started":reason;return ok;}
    public bool TryIssue(string mercenaryId,EatingCommandSourceV3 source,out string reason)
    {
        if(_active.ContainsKey(mercenaryId)){reason="FoodAlreadyReserved";return false;}if(!_mercenaries.CanPlayerControlMercenary(_playerId,mercenaryId)||!_mercenaries.Registry.TryGetState(mercenaryId,out var state)||state==null||state.CompanyId!=_companyId){reason="WorkerCompanyChanged";return false;}_needs.Hunger.EnsureForMercenary(mercenaryId);float hunger=_needs.Hunger.GetHunger(mercenaryId);if(source==EatingCommandSourceV3.DirectOrder&&hunger<=_needs.HungerConfig.MealTargetHunger+.000001f){reason="AlreadyFull";return false;}if(source==EatingCommandSourceV3.NeedAutoEat&&(hunger<_needs.HungerConfig.AutoEatThreshold||state.ActivityState!=MercenaryActivityStateV3.Idle||_work.TryGetAssignment(mercenaryId,out _)||_control.Movements.TryGet(mercenaryId,out _)||_work.Carries.ContainsCarry(mercenaryId))){reason="AutoEatNotEligible";return false;}if(!_work.CanStartFor(mercenaryId,WorkTypeV3.Eating,out reason))return false;if(!TryFindFood(state.CurrentCell,hunger,out var stack,out var spec,out var meal,out var interaction)){reason="NoEdibleFoodAvailable";return false;}
        string workId=WorkRequestIdFactoryV3.Create();long revision=++_revision;if(!_resources.AmountReservations.TryReserve(stack.ResourceStackId,mercenaryId,workId,stack.ResourceType,meal.PlannedUnits,ResourceAmountReservationPurposeV3.FoodConsumption,out var reservation,out reason)||reservation==null)return false;
        if(source==EatingCommandSourceV3.DirectOrder){_work.NotifyExternalWorkSupersede(mercenaryId);_work.CancelForDirectMove(mercenaryId);_control.SupersedeDirectMovementForWork(mercenaryId);}var eating=new EatingWorkStateV3{WorkRequestId=workId,MercenaryId=mercenaryId,CompanyId=_companyId,GroundStackId=stack.ResourceStackId,ReservationId=reservation.ReservationId,FoodDisplayName=spec.DisplayName,ResourceType=stack.ResourceType,CaloriesPerUnit=spec.CaloriesPerUnit,PlannedUnits=meal.PlannedUnits,PlannedCalories=meal.PlannedCalories,RequiredCalories=meal.RequiredCalories,RequiredUnits=meal.RequiredUnits,IsCompleteMeal=meal.IsCompleteMeal,CalorieOvershoot=meal.CalorieOvershoot,FoodStackCell=stack.Cell,InteractionCell=interaction,EatDurationPerUnitSeconds=spec.EatDurationPerUnitSeconds,EatingDurationSeconds=meal.EatingDurationSeconds,StartingHunger=hunger,ExpectedHungerReduction=meal.ExpectedHungerReduction,ExpectedFinalHunger=meal.ExpectedFinalHunger,CommandSource=source,Revision=revision};_active.Add(mercenaryId,eating);
        if(state.CurrentCell.Value==interaction.Value){BeginEating(eating,state);reason=string.Empty;Changed?.Invoke();return true;}if(!_control.ExternalMovements.TryRequest(mercenaryId,state.CurrentCell,interaction,MovementRequestSourceTypeV3.Work,workId,_control.SessionRevision,revision,_control.Movements,out MercenaryMovementRequestV3? movement,out reason)||movement==null){CancelInternal(eating,reason.Length==0?"MovementFailed":reason,EatingWorkPhaseV3.Failed);return false;}eating.MovementRequestId=movement.MovementRequestId;eating.MovementDestinationCell=movement.DestinationCell;Diagnostics.LastExpectedMovementRequestId=movement.MovementRequestId;Diagnostics.LastMovementDestinationCell=movement.DestinationCell;Diagnostics.LastMovementStatus=movement.Status.ToString();reason=string.Empty;Changed?.Invoke();return true;
    }
    public bool TryHandleMovementResult(MercenaryMovementResultV3 result)
    {
        if(!_active.TryGetValue(result.Request.MercenaryId,out var eating)||eating.WorkRequestId!=result.Request.SourceId||eating.Revision!=result.Request.SourceRevision)return false;
        Diagnostics.LastMovementRequestId=result.Request.MovementRequestId;Diagnostics.LastExpectedMovementRequestId=eating.MovementRequestId;Diagnostics.LastMovementStatus=result.Request.Status.ToString();Diagnostics.LastMovementCompletionReason=result.FailureReason;Diagnostics.LastMovementDestinationCell=result.Request.DestinationCell;
        if(eating.MovementRequestId.Length==0||eating.MovementRequestId!=result.Request.MovementRequestId){FailTransition(eating,"MovementCorrelationMismatch");return true;}
        if(!result.Succeeded){FailTransition(eating,result.FailureReason.Length==0?"MovementFailed":result.FailureReason);return true;}
        if(!_mercenaries.Registry.TryGetState(eating.MercenaryId,out var state)||state==null){FailTransition(eating,"WorkerRemoved");return true;}
        Diagnostics.LastWorkerCurrentCell=state.CurrentCell;Diagnostics.LastArrivalMatched=state.CurrentCell.Value==eating.InteractionCell.Value&&result.Request.DestinationCell.Value==eating.InteractionCell.Value;
        if(!Diagnostics.LastArrivalMatched){FailTransition(eating,"EatingArrivalCellMismatch");return true;}
        Diagnostics.LastStackValid=_resources.GroundStacks.TryGet(eating.GroundStackId,out var stack)&&stack!=null&&stack.ResourceType==eating.ResourceType&&stack.Cell.Value==eating.FoodStackCell.Value&&_needs.FoodCatalog.TryGet(stack.ResourceType,out var food)&&food?.CanEatRaw==true;
        Diagnostics.LastReservationValid=_resources.AmountReservations.TryGet(eating.ReservationId,out var held)&&held!=null&&held.MercenaryId==eating.MercenaryId&&held.WorkRequestId==eating.WorkRequestId&&held.GroundStackId==eating.GroundStackId&&held.ResourceType==eating.ResourceType&&held.Amount==eating.PlannedUnits&&held.Purpose==ResourceAmountReservationPurposeV3.FoodConsumption;
        if(!Diagnostics.LastStackValid){FailTransition(eating,"FoodStackInvalidAtArrival");return true;}if(!Diagnostics.LastReservationValid){FailTransition(eating,"FoodReservationLost");return true;}
        BeginEating(eating,state);Diagnostics.LastEatingTransition="MovingToFood->Eating";Diagnostics.LastEatingTransitionFailure=string.Empty;Changed?.Invoke();return true;
    }
    public void Tick(float delta){foreach(var eating in _active.Values.ToList()){if(eating.Phase!=EatingWorkPhaseV3.Eating)continue;if(!_mercenaries.Registry.TryGetState(eating.MercenaryId,out var state)||state==null){CancelInternal(eating,"WorkerRemoved",EatingWorkPhaseV3.Failed);continue;}if(state.CurrentCell.Value!=eating.InteractionCell.Value){CancelInternal(eating,"FoodInteractionCellInvalid",EatingWorkPhaseV3.Failed);continue;}eating.EatingProgressSeconds+=Math.Max(0,delta);if(eating.EatingProgressSeconds<eating.EatingDurationSeconds){Changed?.Invoke();continue;}if(!_resources.AmountReservations.TryGet(eating.ReservationId,out var held)||held==null||held.Amount!=eating.PlannedUnits||held.ResourceType!=eating.ResourceType){CancelInternal(eating,"ReservationMismatch",EatingWorkPhaseV3.Failed);continue;}if(!_needs.FoodCatalog.TryGet(eating.ResourceType,out var spec)||spec?.CanEatRaw!=true){CancelInternal(eating,"InvalidFoodSpec",EatingWorkPhaseV3.Failed);continue;}if(!_resources.AmountReservations.TryConsume(eating.ReservationId,eating.MercenaryId,eating.WorkRequestId,out _,out _,out string reason)){CancelInternal(eating,reason,EatingWorkPhaseV3.Failed);continue;}if(!_resources.ConsumptionLedger.TryRecord(eating.ResourceType,eating.PlannedUnits,"Eating",eating.MercenaryId,eating.WorkRequestId)){CancelInternal(eating,"ConsumptionLedgerFailed",EatingWorkPhaseV3.Failed);continue;}_needs.Hunger.EnsureForMercenary(eating.MercenaryId).TryReduceHunger(eating.ExpectedHungerReduction,out _);eating.Phase=EatingWorkPhaseV3.Completed;_active.Remove(eating.MercenaryId);state.TrySetActivityState(MercenaryActivityStateV3.Idle,out _);Diagnostics.CompletedCount++;ResourcesChanged?.Invoke();Changed?.Invoke();}}
    public bool Cancel(string mercenaryId,string reason){if(!_active.TryGetValue(mercenaryId,out var eating))return false;CancelInternal(eating,reason,EatingWorkPhaseV3.Cancelled);return true;}public bool TryGet(string mercenaryId,out EatingWorkStateV3? state)=>_active.TryGetValue(mercenaryId,out state);
    public int GetAvailableRationAmount()=>GetAvailableFoodAmount(ResourceTypeV3.Ration);public int GetAvailableFoodAmount(ResourceTypeV3 type)=>_resources.GroundStacks.GetAllStackIds().Where(id=>_resources.GroundStacks.TryGet(id,out var s)&&s?.ResourceType==type).Sum(id=>_resources.AmountReservations.GetAvailableAmount(id));
    public bool TryPreviewMeal(string mercenaryId,out ResourceTypeV3 type,out FoodMealPlanV3 plan,out string displayName){type=default;plan=default;displayName=string.Empty;if(!_mercenaries.Registry.TryGetState(mercenaryId,out var state)||state==null||!TryFindFood(state.CurrentCell,_needs.Hunger.GetHunger(mercenaryId),out var stack,out var spec,out plan,out _))return false;type=stack.ResourceType;displayName=spec.DisplayName;return true;}
    private bool TryFindFood(GlobalCellCoord origin,float hunger,out GroundResourceStackV3 stack,out FoodSpecV3 spec,out FoodMealPlanV3 plan,out GlobalCellCoord interaction){stack=null!;spec=null!;plan=default;interaction=default;var candidates=new List<(GroundResourceStackV3 Stack,FoodSpecV3 Spec,FoodMealPlanV3 Plan,float Distance)>();foreach(string id in _resources.GroundStacks.GetAllStackIds()){if(!_resources.GroundStacks.TryGet(id,out var value)||value==null||!_needs.FoodCatalog.TryGet(value.ResourceType,out var food)||food?.CanEatRaw!=true||!_query.IsInsideWorld(value.Cell.Value)||!_query.IsWalkable(value.Cell.Value))continue;int available=_resources.AmountReservations.GetAvailableAmount(id);if(!FoodMealCalculatorV3.TryPlan(hunger,_needs.HungerConfig.MealTargetHunger,_needs.HungerConfig.HungerCalorieCapacity,food,available,out var meal,out _))continue;candidates.Add((value,food,meal,MercenaryMovementCostPolicyV3.Octile(origin.Value,value.Cell.Value)));}var ordered=candidates.OrderByDescending(x=>x.Plan.IsCompleteMeal).ThenByDescending(x=>x.Plan.IsCompleteMeal?0:x.Plan.PlannedCalories).ThenBy(x=>x.Distance).ThenBy(x=>x.Plan.IsCompleteMeal?x.Plan.CalorieOvershoot:0).ThenBy(x=>x.Plan.PlannedUnits).ThenBy(x=>x.Stack.ResourceType).ThenBy(x=>x.Stack.ResourceStackId,StringComparer.Ordinal).FirstOrDefault();if(ordered.Stack==null)return false;stack=ordered.Stack;spec=ordered.Spec;plan=ordered.Plan;interaction=stack.Cell;return true;}
    private static void BeginEating(EatingWorkStateV3 eating,MercenaryStateV3 state){eating.Phase=EatingWorkPhaseV3.Eating;eating.EatingProgressSeconds=0;state.TrySetActivityState(MercenaryActivityStateV3.Working,out _);}
    private void FailTransition(EatingWorkStateV3 eating,string reason){Diagnostics.LastEatingTransitionFailure=reason;CancelInternal(eating,reason,EatingWorkPhaseV3.Failed);}
    private void CancelInternal(EatingWorkStateV3 eating,string reason,EatingWorkPhaseV3 terminal){_resources.AmountReservations.Release(eating.ReservationId);_control.ExternalMovements.Cancel(eating.MercenaryId,reason,_control.Movements);eating.Phase=terminal;eating.FailureReason=reason;_active.Remove(eating.MercenaryId);if(_mercenaries.Registry.TryGetState(eating.MercenaryId,out var state)&&state!=null&&!_control.Movements.TryGet(eating.MercenaryId,out _))state.TrySetActivityState(MercenaryActivityStateV3.Idle,out _);if(terminal==EatingWorkPhaseV3.Cancelled)Diagnostics.CancelledCount++;else Diagnostics.FailedCount++;Diagnostics.LastFailureReason=reason;Changed?.Invoke();}
}

public static class EatingRuntimeSelfCheckV3
{
    public static bool TryValidate(out string reason){Rect2I bounds=new(0,0,20,20);CompanySessionV3 companies=new();if(!companies.TryInitializeLocalSinglePlayer(out _,out reason))return false;string player=companies.LocalPlayer!.PlayerId,company=companies.LocalContext.LocalCompanyId!;MercenarySessionV3 mercenaries=new(companies.CompanyRegistry);MercenaryAttributeSetV3.TryCreate(10,10,10,10,10,out var attributes,out _);MercenaryWorkSkillSetV3.TryCreate(8,8,8,8,8,8,8,out var skills,out _);string id=MercenaryIdFactoryV3.CreateMercenaryId();DateTime now=DateTime.UtcNow;MercenaryProfileV3.TryCreate(id,"Eater","placeholder",attributes,skills,now,out var profile,out _);MercenaryStateV3.TryCreate(id,company,new(new Vector2I(4,4)),MercenaryActivityStateV3.Idle,now,out var state,out _);mercenaries.Registry.TryRegisterMercenary(profile,state,out _);MercenaryControlSessionV3 control=new(1,companies,mercenaries);ResourceSessionV3 resources=new();StockpileSessionV3 stockpiles=new();MercenaryWorkSessionV3 work=new(1,companies,mercenaries,resources,stockpiles,control);control.AttachWorkSession(work);MercenaryNeedsSessionV3 needs=new(1);needs.EnsureMercenaries(mercenaries.Registry);needs.Hunger.EnsureForMercenary(id).TrySetHunger(.65f,out _);resources.GroundStacks.TryAddStack(ResourceTypeV3.Ration,18,state!.CurrentCell,out _,out _,out _);EatingWorkCoordinatorV3 coordinator=new(needs,resources,mercenaries,control,work,new TestQuery(bounds),player,company);if(!coordinator.TryIssueManual(id,out reason)||coordinator.ActiveCount!=1||resources.AmountReservations.Count!=1){reason="Manual eating did not reserve food.";return false;}coordinator.Tick(2.9f);if(resources.GroundStacks.GetTotalAmount(ResourceTypeV3.Ration)!=18||Math.Abs(needs.Hunger.GetHunger(id)-.65f)>.001f){reason="Eating consumed before duration.";return false;}coordinator.Tick(.1f);if(resources.GroundStacks.GetTotalAmount(ResourceTypeV3.Ration)!=17||Math.Abs(needs.Hunger.GetHunger(id)-.20f)>.001f||resources.AmountReservations.Count!=0||resources.ConsumptionLedger.GetConsumedAmount(ResourceTypeV3.Ration)!=1||state.ActivityState!=MercenaryActivityStateV3.Idle){reason="Manual eating completion invariants failed.";return false;}needs.Hunger.EnsureForMercenary(id).TrySetHunger(.65f,out _);if(!coordinator.TryIssueAuto(id,out reason)||coordinator.TryGet(id,out var auto)==false||auto?.CommandSource!=EatingCommandSourceV3.NeedAutoEat){reason="Auto eating did not start.";return false;}coordinator.Cancel(id,"CancelledByDirectMove");if(resources.GroundStacks.GetTotalAmount(ResourceTypeV3.Ration)!=17||resources.AmountReservations.Count!=0||Math.Abs(needs.Hunger.GetHunger(id)-.65f)>.001f){reason="Eating cancellation changed resources or hunger.";return false;}var a=NeedActionPriorityV3.GetCandidates(.90f,.80f,needs.HungerConfig,needs.Settings);var b=NeedActionPriorityV3.GetCandidates(.70f,.95f,needs.HungerConfig,needs.Settings);var c=NeedActionPriorityV3.GetCandidates(.90f,.95f,needs.HungerConfig,needs.Settings);if(a.Count==0||a[0]!=NeedActionKindV3.Eat||b.Count==0||b[0]!=NeedActionKindV3.Rest||c.Count<2||c[0]!=NeedActionKindV3.Eat||c[1]!=NeedActionKindV3.Rest){reason="Eat/rest priority failed.";return false;}reason=string.Empty;return true;}
    private sealed class TestQuery:IMercenaryNavigationWorldQueryV3{private readonly Rect2I _bounds;public TestQuery(Rect2I bounds){_bounds=bounds;}public bool IsInsideWorld(Vector2I cell)=>_bounds.HasPoint(cell);public MercenaryNavigationCellInfoV3 GetCellInfo(Vector2I cell)=>new(IsInsideWorld(cell),IsWalkable(cell),1,TileType.Grass,BiomeKindV3.Plains);public bool IsWalkable(Vector2I cell)=>IsInsideWorld(cell);public float GetTraversalMultiplier(Vector2I cell)=>1;}
}
